/// Merge two YAML values, with the second taking precedence
fn merge_yaml(base: &mut serde_yaml::Value, overlay: serde_yaml::Value) {
    if let (serde_yaml::Value::Mapping(base_map), serde_yaml::Value::Mapping(overlay_map)) =
        (base, overlay)
    {
        for (key, value) in overlay_map {
            if let Some(base_value) = base_map.get_mut(&key) {
                if value.is_mapping() && base_value.is_mapping() {
                    merge_yaml(base_value, value);
                } else {
                    *base_value = value;
                }
            } else {
                base_map.insert(key, value);
            }
        }
    }
}

/// Expand environment variable references in config
fn expand_env_vars(content: &str) -> String {
    let mut result = content.to_string();
    let re = regex::Regex::new(r"\$\{([A-Z_][A-Z0-9_]*)(?::([^}]*))?\}").unwrap();

    for cap in re.captures_iter(content) {
        let full_match = cap.get(0).unwrap().as_str();
        let var_name = cap.get(1).unwrap().as_str();
        let default_value = cap.get(2).map(|m| m.as_str()).unwrap_or("");

        let value = std::env::var(var_name).unwrap_or_else(|_| default_value.to_string());
        result = result.replace(full_match, &value);
    }

    result
}
